1	<script lang="ts">
2	  import { walkthrough } from '$lib/walkthrough/walkthrough.svelte';
3	
4	  // Digit-input jump: typing a number buffers it. 1s after the last
5	  // keystroke, the buffer is committed as a 1-indexed segment number
6	  // and the camera jumps there. Any non-digit keystroke cancels the
7	  // pending jump so arrow nav doesn't get mixed up with a typed number.
8	  const JUMP_TIMEOUT_MS = 1000;
9	  let jumpBuffer = $state('');
10	  let jumpTimer: number | null = null;
11	
12	  function commitJump() {
13	    const n = parseInt(jumpBuffer, 10);
14	    jumpBuffer = '';
15	    jumpTimer = null;
16	    if (!Number.isFinite(n) || n < 1) return;
17	    walkthrough.jumpTo(n - 1);
18	  }
19	
20	  function cancelJump() {
21	    jumpBuffer = '';
22	    if (jumpTimer != null) {
23	      clearTimeout(jumpTimer);
24	      jumpTimer = null;
25	    }
26	  }
27	
28	  function handleKeydown(e: KeyboardEvent) {
29	    // Swallow digits into the jump buffer and (re)start the debounce.
30	    if (/^[0-9]$/.test(e.key) && !e.metaKey && !e.ctrlKey && !e.altKey) {
31	      e.preventDefault();
32	      jumpBuffer += e.key;
33	      if (jumpTimer != null) clearTimeout(jumpTimer);
34	      jumpTimer = window.setTimeout(commitJump, JUMP_TIMEOUT_MS);
35	      return;
36	    }
37	
38	    // Any other key aborts a pending jump so it doesn't fire later.
39	    cancelJump();
40	
41	    switch (e.key) {
42	      // Within-segment progression
43	      case 'ArrowDown':
44	      case ' ':
45	      case 'Enter':
46	      case 'PageDown':
47	        e.preventDefault();
48	        walkthrough.stepNext();
49	        break;
50	      case 'ArrowUp':
51	      case 'Backspace':
52	      case 'PageUp':
53	        e.preventDefault();
54	        walkthrough.stepPrev();
55	        break;
56	
57	      // Cross-segment navigation
58	      case 'ArrowRight':
59	        e.preventDefault();
60	        walkthrough.switchNext();
61	        break;
62	      case 'ArrowLeft':
63	        e.preventDefault();
64	        walkthrough.switchPrev();
65	        break;
66	    }
67	  }
68	</script>
69	
70	<svelte:window onkeydown={handleKeydown} />
