let connected = $state(false);
let status = $state<Status>('ready');
let source: EventSource | null = null;

const LABELS: Record<Status, string> = {
  'ready': 'ready',
  'working': 'working',
  'input-needed': 'input needed'
};

function connect() {
  try {
    source = new EventSource(BRIDGE_URL);
  } catch {
    return;
  }
  source.onopen = () => { connected = true; };
  source.onmessage = (e) => {
    try {
      const msg = JSON.parse(e.data);
      if (msg && typeof msg.status === 'string') {
        if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
          status = msg.status;
          connected = true;
        }
      }
    } catch { /* ignore malformed */ }
  };
  // EventSource auto-reconnects. We flip `connected` off on error so the
  // UI hides while it's retrying; if the bridge is truly gone, it just
  // stays hidden, which is the desired behavior.
  source.onerror = () => { connected = false; };
}

input.new_string:
let connected = $state(false);
let status = $state<Status>('ready');
let source: EventSource | null = null;
let everConnected = false;
let givenUp = false;

const LABELS: Record<Status, string> = {
  'ready': 'ready',
  'working': 'working',
  'input-needed': 'input needed'
};

function connect() {
  try {
    source = new EventSource(BRIDGE_URL);
  } catch {
    return;
  }
  source.onopen = () => {
    connected = true;
    everConnected = true;
  };
  source.onmessage = (e) => {
    try {
      const msg = JSON.parse(e.data);
      if (msg && typeof msg.status === 'string') {
        if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
          status = msg.status;
          connected = true;
          everConnected = true;
        }
      }
    } catch { /* ignore malformed */ }
  };
  // Hide on error. If we never reached the bridge at all, give up after
  // the first failure so the compiled single-file build doesn't spam
  // connection attempts on a student's machine. Once we've connected at
  // least once, EventSource's built-in reconnect is fine.
  source.onerror = () => {
    connected = false;
    if (!everConnected && !givenUp) {
      givenUp = true;
      source?.close();
      source = null;
    }
  };
}

