2	  import { walkthrough } from './walkthrough.svelte';
3	  import { STAGE_WIDTH, STAGE_HEIGHT } from '$lib/constants';
4	
5	  // Scale the nav bar with the rest of the stage so it does not look
6	  // disproportionately large on small windows. Mirrors the fitScale
7	  // computation in CameraViewport.
8	  let winW = $state(window.innerWidth);
9	  let winH = $state(window.innerHeight);
10	  const fitScale = $derived(
11	    Math.min(winW / STAGE_WIDTH, winH / STAGE_HEIGHT),
12	  );
13	
14	  function onResize() {
