1	<script lang="ts">
2	  // Subtle top-right indicator that reflects what Claude Code is doing in
3	  // the background, fed by scripts/status-bridge.mjs over SSE. If the
4	  // bridge isn't running (e.g. the compiled single-file HTML a student
5	  // opens), the component stays invisible - no broken UI in the wild.
6	
7	  type Status = 'ready' | 'working' | 'input-needed';
8	
9	  const BRIDGE_URL = 'http://127.0.0.1:7321/events';
10	
11	  let connected = $state(false);
12	  let status = $state<Status>('ready');
13	  let source: EventSource | null = null;
14	  let everConnected = false;
15	  let givenUp = false;
16	
17	  const LABELS: Record<Status, string> = {
18	    'ready': 'ready',
19	    'working': 'working',
20	    'input-needed': 'input needed'
21	  };
22	
23	  function connect() {
24	    try {
25	      source = new EventSource(BRIDGE_URL);
26	    } catch {
27	      return;
28	    }
29	    source.onopen = () => {
30	      connected = true;
31	      everConnected = true;
32	    };
33	    source.onmessage = (e) => {
34	      try {
35	        const msg = JSON.parse(e.data);
36	        if (msg && typeof msg.status === 'string') {
37	          if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
38	            status = msg.status;
39	            connected = true;
40	            everConnected = true;
41	          }
42	        }
43	      } catch { /* ignore malformed */ }
44	    };
45	    // Hide on error. If we never reached the bridge at all, give up after
46	    // the first failure so the compiled single-file build doesn't spam
47	    // connection attempts on a student's machine. Once we've connected at
48	    // least once, EventSource's built-in reconnect is fine.
49	    source.onerror = () => {
50	      connected = false;
51	      if (!everConnected && !givenUp) {
52	        givenUp = true;
53	        source?.close();
54	        source = null;
55	      }
56	    };
57	  }
58	
59	  $effect(() => {
60	    connect();
61	    return () => {
62	      source?.close();
63	      source = null;
64	    };
65	  });
66	</script>
67	
68	{#if connected}
69	  <div class="status-indicator" data-status={status} aria-live="polite">
70	    <span class="dot"></span>
71	    <span class="label">{LABELS[status]}</span>
72	  </div>
73	{/if}
74	
75	<style>
76	  .status-indicator {
77	    position: fixed;
78	    top: 20px;
79	    right: 20px;
80	    display: inline-flex;
81	    align-items: center;
82	    gap: 10px;
83	    padding: 6px 12px 6px 10px;
84	    border-radius: 9999px;
85	    background: rgba(0, 0, 0, 0.42);
86	    border: 1px solid rgba(255, 255, 255, 0.08);
87	    backdrop-filter: blur(10px);
88	    -webkit-backdrop-filter: blur(10px);
89	    font-family: 'JetBrains Mono', ui-monospace, Menlo, monospace;
90	    font-size: 11px;
91	    letter-spacing: 0.14em;
92	    text-transform: uppercase;
93	    color: rgba(255, 255, 255, 0.62);
94	    z-index: 1000;
95	    pointer-events: none;
96	    user-select: none;
97	    transition: background 0.3s ease, border-color 0.3s ease, color 0.3s ease;
98	    animation: si-fade-in 0.4s ease-out;
99	  }
100	
101	  .dot {
102	    width: 8px;
103	    height: 8px;
104	    border-radius: 50%;
105	    background: var(--dot-color, #10b981);
106	    box-shadow: 0 0 0 0 var(--dot-glow, rgba(16, 185, 129, 0.4));
107	    transition: background 0.3s ease;
108	  }
109	
110	  /* Ready: calm green, no motion. */
111	  .status-indicator[data-status='ready'] {
112	    --dot-color: #10b981;
113	  }
114	
115	  /* Working: amber, slow breathing pulse. */
116	  .status-indicator[data-status='working'] {
117	    --dot-color: #f59e0b;
118	    --dot-glow: rgba(245, 158, 11, 0.55);
119	    color: rgba(255, 255, 255, 0.78);
120	  }
121	  .status-indicator[data-status='working'] .dot {
122	    animation: si-pulse-slow 2.2s ease-in-out infinite;
123	  }
124	
125	  /* Input needed: pink, urgent pulse + border accent so it catches the eye. */
126	  .status-indicator[data-status='input-needed'] {
127	    --dot-color: #ec4899;
128	    --dot-glow: rgba(236, 72, 153, 0.7);
129	    color: #fff;
130	    border-color: rgba(236, 72, 153, 0.55);
131	    background: rgba(48, 10, 30, 0.55);
132	  }
133	  .status-indicator[data-status='input-needed'] .dot {
134	    animation: si-pulse-fast 0.9s ease-in-out infinite;
135	  }
136	
137	  @keyframes si-pulse-slow {
138	    0%, 100% {
139	      box-shadow: 0 0 0 0 var(--dot-glow);
140	      transform: scale(1);
141	    }
142	    50% {
143	      box-shadow: 0 0 0 6px rgba(0, 0, 0, 0);
144	      transform: scale(1.15);
145	    }
146	  }
147	
148	  @keyframes si-pulse-fast {
149	    0%, 100% {
150	      box-shadow: 0 0 0 0 var(--dot-glow);
151	      transform: scale(1);
152	    }
153	    50% {
154	      box-shadow: 0 0 0 8px rgba(0, 0, 0, 0);
155	      transform: scale(1.35);
156	    }
157	  }
158	
159	  @keyframes si-fade-in {
160	    from { opacity: 0; transform: translateY(-4px); }
161	    to   { opacity: 1; transform: translateY(0); }
162	  }
163	</style>
164

