1	<script lang="ts">
2	  // Subtle top-right indicator that reflects what Claude Code is doing in
3	  // the background, fed by scripts/status-bridge.mjs over SSE. If the
4	  // bridge isn't running (e.g. the compiled single-file HTML a student
5	  // opens), the component stays invisible - no broken UI in the wild.
6	
7	  import { STAGE_WIDTH, STAGE_HEIGHT } from '$lib/constants';
8	
9	  type Status = 'ready' | 'working' | 'input-needed';
10	
11	  const BRIDGE_URL = 'http://127.0.0.1:7321/events';
12	
13	  let connected = $state(false);
14	  let status = $state<Status>('ready');
15	  let source: EventSource | null = null;
16	  let everConnected = false;
17	  let givenUp = false;
18	
19	  // Scale the indicator with the rest of the stage, matching the nav bar.
20	  let winW = $state(window.innerWidth);
21	  let winH = $state(window.innerHeight);
22	  const fitScale = $derived(
23	    Math.min(winW / STAGE_WIDTH, winH / STAGE_HEIGHT),
24	  );
25	
26	  function onResize() {
27	    winW = window.innerWidth;
28	    winH = window.innerHeight;
29	  }
30	
31	  const LABELS: Record<Status, string> = {
32	    'ready': 'ready',
33	    'working': 'working',
34	    'input-needed': 'input needed'
35	  };
36	
37	  function connect() {
38	    try {
39	      source = new EventSource(BRIDGE_URL);
40	    } catch {
41	      return;
42	    }
43	    source.onopen = () => {
44	      connected = true;
45	      everConnected = true;
46	    };
47	    source.onmessage = (e) => {
48	      try {
49	        const msg = JSON.parse(e.data);
50	        if (msg && typeof msg.status === 'string') {
51	          if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
52	            status = msg.status;
53	            connected = true;
54	            everConnected = true;
55	          }
56	        }
57	      } catch { /* ignore malformed */ }
58	    };
59	    // Hide on error. If we never reached the bridge at all, give up after
60	    // the first failure so the compiled single-file build doesn't spam
61	    // connection attempts on a student's machine. Once we've connected at
62	    // least once, EventSource's built-in reconnect is fine.
63	    source.onerror = () => {
64	      connected = false;
65	      if (!everConnected && !givenUp) {
66	        givenUp = true;
67	        source?.close();
68	        source = null;
69	      }
70	    };
71	  }
72	
73	  $effect(() => {
74	    connect();
75	    return () => {
76	      source?.close();
77	      source = null;
78	    };
79	  });
80	</script>
81	
82	<svelte:window onresize={onResize} />
83	
84	{#if connected}
85	  <div
86	    class="status-indicator"
87	    data-status={status}
88	    style:zoom={fitScale}
89	    aria-live="polite"
90	  >
91	    <span class="ai-mark" aria-hidden="true">
92	      <svg viewBox="0 0 24 24" width="20" height="20">
93	        <defs>
94	          <linearGradient id="ai-mark-grad" x1="0" y1="0" x2="1" y2="1">
95	            <stop offset="0%" stop-color="#c084fc" />
96	            <stop offset="100%" stop-color="#7c3aed" />
97	          </linearGradient>
98	        </defs>
99	        <circle cx="12" cy="12" r="11" fill="url(#ai-mark-grad)" />
100	        <path
101	          d="M12 5 L13.2 10.8 L19 12 L13.2 13.2 L12 19 L10.8 13.2 L5 12 L10.8 10.8 Z"
102	          fill="#fff"
103	        />
104	      </svg>
105	    </span>
106	    <span class="dot"></span>
107	    <span class="label">{LABELS[status]}</span>
108	  </div>
109	{/if}
110	
111	<style>
112	  .status-indicator {
113	    position: fixed;
114	    top: 24px;
115	    right: 24px;
116	    display: inline-flex;
117	    align-items: center;
118	    gap: 12px;
119	    padding: 7px 18px 7px 7px;
120	    border-radius: 9999px;
121	    background: rgba(0, 0, 0, 0.42);
122	    border: 1px solid rgba(255, 255, 255, 0.08);
123	    backdrop-filter: blur(10px);
124	    -webkit-backdrop-filter: blur(10px);
125	    font-family: 'JetBrains Mono', ui-monospace, Menlo, monospace;
126	    font-size: 13px;
127	    letter-spacing: 0.14em;
128	    text-transform: uppercase;
129	    color: rgba(255, 255, 255, 0.62);
130	    z-index: 1000;
131	    pointer-events: none;
132	    user-select: none;
133	    transition: background 0.3s ease, border-color 0.3s ease, color 0.3s ease;
134	    animation: si-fade-in 0.4s ease-out;
135	  }
136	
137	  .dot {
138	    width: 10px;
139	    height: 10px;
140	    border-radius: 50%;
141	    background: var(--dot-color, #10b981);
142	    box-shadow: 0 0 0 0 var(--dot-glow, rgba(16, 185, 129, 0.4));
143	    transition: background 0.3s ease;
144	  }
145	
