171	  .status-indicator[data-status='input-needed'] {
172	    --dot-color: #ec4899;
173	    --dot-glow: rgba(236, 72, 153, 0.7);
174	    color: #fff;
175	    border-color: rgba(236, 72, 153, 0.55);
176	    background: rgba(48, 10, 30, 0.55);
177	  }
178	  .status-indicator[data-status='input-needed'] .dot {
179	    animation: si-pulse-fast 0.9s ease-in-out infinite;
180	  }
181	
182	  @keyframes si-pulse-slow {
183	    0%, 100% {
184	      box-shadow: 0 0 0 0 var(--dot-glow);
185	      transform: scale(1);
186	    }
187	    50% {
188	      box-shadow: 0 0 0 6px rgba(0, 0, 0, 0);
189	      transform: scale(1.15);
190	    }
191	  }
192	
193	  @keyframes si-pulse-fast {
194	    0%, 100% {
195	      box-shadow: 0 0 0 0 var(--dot-glow);
196	      transform: scale(1);
197	    }
198	    50% {
199	      box-shadow: 0 0 0 8px rgba(0, 0, 0, 0);
200	      transform: scale(1.35);
201	    }
202	  }
203	
204	  @keyframes si-fade-in {
205	    from { opacity: 0; transform: translateY(-4px); }
206	    to   { opacity: 1; transform: translateY(0); }
207	  }
