input.old_string:
.dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--dot-color, #10b981);
  box-shadow: 0 0 0 0 var(--dot-glow, rgba(16, 185, 129, 0.4));
  transition: background 0.3s ease;
}

.ai-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  filter: drop-shadow(0 0 6px rgba(124, 58, 237, 0.45));
}

/* Ready: calm green, no motion. */
.status-indicator[data-status='ready'] {
  --dot-color: #10b981;
}

/* Working: amber, slow breathing pulse. */
.status-indicator[data-status='working'] {
  --dot-color: #f59e0b;
  --dot-glow: rgba(245, 158, 11, 0.55);
  color: rgba(255, 255, 255, 0.78);
}
.status-indicator[data-status='working'] .dot {
  animation: si-pulse-slow 2.2s ease-in-out infinite;
}

/* Input needed: pink, urgent pulse + border accent so it catches the eye. */
.status-indicator[data-status='input-needed'] {
  --dot-color: #ec4899;
  --dot-glow: rgba(236, 72, 153, 0.7);
  color: #fff;
  border-color: rgba(236, 72, 153, 0.55);
  background: rgba(48, 10, 30, 0.55);
}
.status-indicator[data-status='input-needed'] .dot {
  animation: si-pulse-fast 0.9s ease-in-out infinite;
}

@keyframes si-pulse-slow {
  0%, 100% {
    box-shadow: 0 0 0 0 var(--dot-glow);
    transform: scale(1);
  }
  50% {
    box-shadow: 0 0 0 6px rgba(0, 0, 0, 0);
    transform: scale(1.15);
  }
}

@keyframes si-pulse-fast {
  0%, 100% {
    box-shadow: 0 0 0 0 var(--dot-glow);
    transform: scale(1);
  }
  50% {
    box-shadow: 0 0 0 8px rgba(0, 0, 0, 0);
    transform: scale(1.35);
  }
}

input.new_string:
.ai-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 24px;
  height: 24px;
  filter: drop-shadow(0 0 6px var(--mark-glow, rgba(16, 185, 129, 0.5)));
  transition: filter 0.3s ease;
}

/* The gradient stops are driven by CSS custom properties so the AI mark
   recolors with the current status and doubles as the state indicator. */
:global(.mark-stop-from) {
  stop-color: var(--mark-from, #34d399);
  transition: stop-color 0.3s ease;
}
:global(.mark-stop-to) {
  stop-color: var(--mark-to, #059669);
  transition: stop-color 0.3s ease;
}

/* Ready: calm green, no motion. */
.status-indicator[data-status='ready'] {
  --mark-from: #34d399;
  --mark-to: #059669;
  --mark-glow: rgba(16, 185, 129, 0.5);
}

/* Working: amber, slow breathing pulse. */
.status-indicator[data-status='working'] {
  --mark-from: #fbbf24;
  --mark-to: #d97706;
  --mark-glow: rgba(245, 158, 11, 0.6);
  color: rgba(255, 255, 255, 0.78);
}
.status-indicator[data-status='working'] .ai-mark {
  animation: si-pulse-slow 2.2s ease-in-out infinite;
}

/* Input needed: pink, urgent pulse + border accent so it catches the eye. */
.status-indicator[data-status='input-needed'] {
  --mark-from: #f472b6;
  --mark-to: #db2777;
  --mark-glow: rgba(236, 72, 153, 0.75);
  color: #fff;
  border-color: rgba(236, 72, 153, 0.55);
  background: rgba(48, 10, 30, 0.55);
}
.status-indicator[data-status='input-needed'] .ai-mark {
  animation: si-pulse-fast 0.9s ease-in-out infinite;
}

@keyframes si-pulse-slow {
  0%, 100% {
    transform: scale(1);
    filter: drop-shadow(0 0 6px var(--mark-glow));
  }
  50% {
    transform: scale(1.1);
    filter: drop-shadow(0 0 14px var(--mark-glow));
  }
}

@keyframes si-pulse-fast {
  0%, 100% {
    transform: scale(1);
    filter: drop-shadow(0 0 6px var(--mark-glow));
  }
  50% {
    transform: scale(1.2);
    filter: drop-shadow(0 0 18px var(--mark-glow));
  }
}

