32	    'ready': 'ready',
33	    'working': 'working',
34	    'input-needed': 'input needed'
35	  };
36	
37	  function connect() {
38	    try {
39	      source = new EventSource(BRIDGE_URL);
40	    } catch {
41	      return;
42	    }
43	    source.onopen = () => {
44	      connected = true;
45	      everConnected = true;
46	    };
47	    source.onmessage = (e) => {
48	      try {
49	        const msg = JSON.parse(e.data);
50	        if (msg && typeof msg.status === 'string') {
51	          if (msg.status === 'ready' || msg.status === 'working' || msg.status === 'input-needed') {
52	            status = msg.status;
53	            connected = true;
54	            everConnected = true;
55	          }
56	        }
57	      } catch { /* ignore malformed */ }
58	    };
59	    // Hide on error. If we never reached the bridge at all, give up after
60	    // the first failure so the compiled single-file build doesn't spam
61	    // connection attempts on a student's machine. Once we've connected at
62	    // least once, EventSource's built-in reconnect is fine.
63	    source.onerror = () => {
64	      connected = false;
65	      if (!everConnected && !givenUp) {
66	        givenUp = true;
67	        source?.close();
68	        source = null;
69	      }
70	    };
71	  }
72	
73	  $effect(() => {
74	    connect();
75	    return () => {
76	      source?.close();
77	      source = null;
78	    };
79	  });
