/* Ready-burst: nova rings + outward particles, fired when status flips
   into ready. Overflows the mark container; pointer-events disabled so
   it never intercepts input. */
.burst {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 2;
  overflow: visible;
}

.ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 2px solid #34d399;
  opacity: 0;
  transform: scale(0.65);
  animation: burst-ring 1.15s cubic-bezier(0.16, 0.84, 0.44, 1) forwards;
}
.ring-2 { animation-delay: 140ms; border-color: #6ee7b7; }
.ring-3 { animation-delay: 280ms; border-color: #a7f3d0; }

.particle {
  --angle: 0deg;
  --dist: 60px;
  --delay: 0ms;
  position: absolute;
  left: 50%;
  top: 50%;
  width: 5px;
  height: 5px;
  margin: -2.5px 0 0 -2.5px;
  border-radius: 50%;
  background: #34d399;
  box-shadow: 0 0 8px rgba(52, 211, 153, 0.85);
  opacity: 0;
  animation: burst-particle 1.1s ease-out var(--delay) forwards;
}

@keyframes burst-ring {
  0%   { transform: scale(0.65); opacity: 0.85; border-width: 3px; }
  60%  { opacity: 0.35; }
  100% { transform: scale(2.8); opacity: 0; border-width: 0.5px; }
}

@keyframes burst-particle {
  0% {
    opacity: 0;
    transform: rotate(var(--angle)) translateX(14px) scale(0.4);
  }
  15% {
    opacity: 1;
    transform: rotate(var(--angle)) translateX(18px) scale(1);
